<script setup lang="ts">
const schoolModules=useSchoolModules();await schoolModules.ready;const{modules}=schoolModules;const now=ref(Date.now());let timer:ReturnType<typeof setInterval>|undefined;onMounted(()=>timer=setInterval(()=>now.value=Date.now(),1000));onBeforeUnmount(()=>clearInterval(timer));const start=computed(()=>new Date(modules.value.ppdb.startDate).getTime());const end=computed(()=>new Date(modules.value.ppdb.endDate).getTime());const target=computed(()=>now.value<start.value?start.value:end.value);const remaining=computed(()=>Math.max(0,target.value-now.value));const countdown=computed(()=>{const total=Math.floor(remaining.value/1000);return{days:Math.floor(total/86400),hours:Math.floor(total%86400/3600),minutes:Math.floor(total%3600/60),seconds:total%60}});const status=computed(()=>now.value<start.value?'Pendaftaran belum dibuka':now.value<=end.value?'Pendaftaran sedang dibuka':'Pendaftaran telah selesai');useSchoolSeo(()=>modules.value.ppdb.title,()=>modules.value.ppdb.description)
</script>
<template><div><section class="bg-school-navy py-16 text-white"><div class="container-school grid items-center gap-10 lg:grid-cols-2"><div><p class="font-hand text-3xl text-school-yellow">PPDB</p><h1 class="font-display mt-2 text-5xl">{{modules.ppdb.title}}</h1><p class="mt-5 leading-8 text-blue-100">{{modules.ppdb.description}}</p><p class="mt-5 inline-flex rounded-full bg-white/10 px-4 py-2 font-bold">{{status}}</p><div v-if="modules.ppdb.countdownEnabled&&remaining>0" class="mt-7 grid max-w-lg grid-cols-4 gap-3"><div v-for="(value,label) in countdown" :key="label" class="rounded-xl bg-white/10 p-4 text-center"><b class="text-3xl">{{value}}</b><small class="block capitalize text-blue-100">{{label}}</small></div></div><p class="mt-6 text-sm text-blue-100">{{new Date(modules.ppdb.startDate).toLocaleString('id-ID')}} — {{new Date(modules.ppdb.endDate).toLocaleString('id-ID')}}</p></div><img :src="modules.ppdb.image" alt="PPDB" class="mx-auto aspect-square w-full max-w-md rounded-3xl bg-white object-contain p-8"></div></section><div class="container-school grid gap-8 py-14 lg:grid-cols-2"><section class="card p-7"><h2 class="font-display text-3xl text-school-navy">Syarat PPDB</h2><ol class="mt-6 grid gap-3"><li v-for="(item,index) in modules.ppdb.requirements" :key="item.id" class="flex gap-3"><span class="grid size-8 shrink-0 place-items-center rounded-full bg-school-sky font-bold text-school-action">{{index+1}}</span>{{item.text}}</li></ol></section><section class="card p-7"><h2 class="font-display text-3xl text-school-navy">Alur PPDB</h2><ol class="mt-6 grid gap-4"><li v-for="(item,index) in modules.ppdb.steps" :key="item.id"><b class="text-school-navy">{{index+1}}. {{item.title}}</b><p class="text-sm text-muted">{{item.description}}</p></li></ol></section><section class="card p-7 lg:col-span-2"><h2 class="font-display text-3xl text-school-navy">Pertanyaan Umum</h2><details v-for="item in modules.ppdb.faqs" :key="item.id" class="mt-4 rounded-xl border border-line p-4"><summary class="cursor-pointer font-bold text-school-navy">{{item.question}}</summary><p class="mt-3 text-muted">{{item.answer}}</p></details></section></div></div></template>
